public PeriodFormatterBuilder appendYears(){  
    DateTimeField year = new AbstractDateTimeField() {
      @Override public String getName() {
        return "year";
      }
      @Override public int getDurationType() {
        return YEARS;
      }
      @Override public long getDifference(long time) {
        return getInstant(time).get(YEAR);
      }
      @Override public long set(long baseTime, long value) {
        return setYear(baseTime, (int)value);
      }
    }; 
    appendField(year); 
    return this;
}


public PeriodFormatterBuilder appendSeparatorIfFieldsAfter(String separator){  
    OptionalFields after=new OptionalFields() { 
      public void appendFields(Appendable buffer,long period,PeriodFormatter formatter) throws IOException { 
         if(formatter.fields().size()-fields.size()>0){
             buffer.append(separator);
         }for(DateTimeField field : fields){ 
             long value=field.getDifference(period); 
              if(value!=0){ 
                 field.serialize(buffer,value);
             }
          }
       }}; 
     after.setFields(fields); 
     append(after); 
    return this;
}

